INSERT INTO articles (title, slug, summary, content, threat_level, category, cves, affected_products, threat_actors, industries, attack_vector, source, source_url, published_at, updated_at, discovered_at, exploited_at, patched_at, verified, verified_by, tags, region) VALUES
('ENISA Publishes 2026 Threat Landscape Report — Ransomware and AI Threats Dominate', 'enisa-2026-threat-landscape-report', 'ENISA annual report identifies ransomware, AI-enabled threats, and supply chain attacks as the top three cyber threats facing Europe in 2026.', 'The European Union Agency for Cybersecurity (ENISA) published its 2026 Threat Landscape report, identifying ransomware-as-a-service, AI-enabled social engineering, and software supply chain compromise as the top three threats. The report notes a 67% increase in ransomware incidents targeting EU critical infrastructure and highlights the growing use of generative AI in phishing campaigns. ENISA recommends increased investment in cyber resilience, cross-border incident response, and AI security research.', 'low', 'vulnerability', '{}', '{"N/A"}', '{}', '{"government","technology","finance","healthcare","energy"}', 'N/A — Intelligence Report', 'ENISA', 'https://www.enisa.europa.eu', '2026-03-19T08:00:00Z', '2026-03-19T08:00:00Z', NULL, NULL, NULL, true, '{"ENISA"}', '{"threat-landscape","report","europe","ransomware","ai-threats"}', 'Europe'),

('CISA Releases Updated Zero Trust Maturity Model v3.0', 'cisa-zero-trust-maturity-model-v3', 'CISA publishes Zero Trust Maturity Model v3.0 with updated guidance for identity, devices, networks, applications, and data pillars.', 'CISA released version 3.0 of its Zero Trust Maturity Model, incorporating lessons from federal agency implementations and adding guidance for AI workloads, cloud-native architectures, and OT environments. The updated model introduces an "Advanced Plus" maturity level and includes specific metrics for measuring zero trust implementation progress. Federal agencies have until FY2027 to achieve "Advanced" maturity.', 'low', 'vulnerability', '{}', '{"N/A"}', '{}', '{"government","technology","defense"}', 'N/A — Guidance Document', 'CISA', 'https://www.cisa.gov/zero-trust-maturity-model', '2026-03-17T10:00:00Z', '2026-03-17T10:00:00Z', NULL, NULL, NULL, true, '{"CISA"}', '{"zero-trust","framework","guidance","federal","compliance"}', 'United States'),

('OpenAI Discloses State-Sponsored Misuse of ChatGPT for Cyber Operations', 'openai-state-sponsored-chatgpt-misuse', 'OpenAI reports disrupting five state-sponsored groups using ChatGPT for reconnaissance, phishing content generation, and malware debugging.', 'OpenAI disclosed that it disrupted accounts linked to five state-sponsored threat actors from China, Iran, North Korea, and Russia using ChatGPT for cyber operations support. Activities included target reconnaissance, phishing email drafting, malware code debugging, and social engineering script development. OpenAI emphasizes that AI provided incremental capability improvements rather than breakthrough capabilities. The company has enhanced its detection systems for coordinated inauthentic usage patterns.', 'medium', 'apt', '{}', '{"ChatGPT","AI Language Models","Generative AI Platforms"}', '{"APT28","APT29","Lazarus Group"}', '{"technology","government","defense"}', 'AI Misuse / Reconnaissance and Content Generation', 'OpenAI Threat Intelligence', 'https://openai.com/blog', '2026-03-14T14:00:00Z', '2026-03-15T08:00:00Z', NULL, NULL, NULL, true, '{"OpenAI"}', '{"ai","chatgpt","state-sponsored","misuse","reconnaissance"}', 'Global'),

('Major Credential Stuffing Campaign Targets Streaming Services — 500K Accounts Compromised', 'credential-stuffing-streaming-500k-accounts', 'Massive credential stuffing campaign compromises 500,000+ streaming service accounts across three major platforms. Accounts sold on dark web.', 'A coordinated credential stuffing campaign has compromised over 500,000 accounts across three major streaming platforms using credential lists from recent data breaches. Compromised accounts are sold on dark web marketplaces for $2-5 each. The campaign uses residential proxy networks to evade rate limiting and bot detection. Affected platforms have initiated forced password resets and are implementing enhanced bot detection. Users are urged to enable MFA and avoid credential reuse.', 'medium', 'data-breach', '{}', '{"Streaming Platforms","Consumer Accounts","Authentication Systems"}', '{}', '{"technology","retail"}', 'Credential Stuffing / Residential Proxy Networks', 'Recorded Future / SpyCloud', 'https://www.recordedfuture.com', '2026-03-11T13:00:00Z', '2026-03-12T10:00:00Z', '2026-03-08T00:00:00Z', NULL, NULL, true, '{"Recorded Future","SpyCloud"}', '{"credential-stuffing","consumer","streaming","dark-web","account-takeover"}', 'Global'),

('SEC Proposes Updated Cybersecurity Incident Reporting Rules for Public Companies', 'sec-updated-cyber-incident-reporting', 'SEC proposes amendments requiring public companies to report material cyber incidents within 48 hours, down from 4 business days.', 'The SEC has proposed amendments to its cybersecurity incident reporting rules that would shorten the material incident reporting deadline from four business days to 48 hours. The proposal also requires quarterly disclosure of cyber risk management metrics and board-level cyber expertise. The rule change comes after criticism that the current four-day window allows too much time for market manipulation. Public comment period runs through May 2026.', 'low', 'vulnerability', '{}', '{"N/A"}', '{}', '{"finance","technology","healthcare","energy","retail"}', 'N/A — Regulatory Action', 'SEC', 'https://www.sec.gov', '2026-03-07T15:00:00Z', '2026-03-08T10:00:00Z', NULL, NULL, NULL, true, '{"SEC"}', '{"regulation","sec","disclosure","compliance","governance"}', 'United States'),

('North Korean IT Workers Infiltrate Fortune 500 Companies via Remote Positions', 'north-korean-it-workers-fortune-500', 'DOJ charges 14 North Korean nationals operating as remote IT workers at Fortune 500 companies. $88M in wages funneled to DPRK regime.', 'The Department of Justice has charged 14 North Korean nationals who obtained remote IT positions at Fortune 500 companies using stolen American identities. The workers used AI-generated profile photos and laptop farms in the US operated by facilitators. Over $88 million in wages were funneled to North Korea weapons programs. Companies in technology, finance, and healthcare were affected. The DOJ recommends enhanced identity verification for remote hiring.', 'medium', 'insider-threat', '{}', '{"Remote Work Platforms","Identity Verification Systems","HR Systems"}', '{"Lazarus Group"}', '{"technology","finance","healthcare","defense"}', 'Identity Fraud / Insider Access', 'DOJ / FBI', 'https://www.justice.gov', '2026-03-05T14:00:00Z', '2026-03-06T10:00:00Z', NULL, NULL, NULL, true, '{"DOJ","FBI"}', '{"north-korea","insider-threat","identity-fraud","remote-work","sanctions"}', 'United States'),

('Jenkins Security Advisory Patches Critical RCE in Pipeline Plugin', 'jenkins-pipeline-plugin-critical-rce', 'Critical deserialization vulnerability in Jenkins Pipeline plugin allows unauthenticated RCE. 150,000+ Jenkins instances exposed.', 'CVE-2026-4321 is a Java deserialization vulnerability in the Jenkins Pipeline: Groovy plugin allowing unauthenticated attackers to execute arbitrary code on Jenkins controllers. Shodan data shows over 150,000 internet-facing Jenkins instances, many running the vulnerable plugin version. Active exploitation detected within 72 hours of advisory publication.', 'high', 'vulnerability', '{"CVE-2026-4321"}', '{"Jenkins","Jenkins Pipeline Plugin","Java","CI/CD Infrastructure"}', '{}', '{"technology","finance","government"}', 'Web / Java Deserialization', 'Jenkins Security Advisory', 'https://www.jenkins.io/security', '2026-03-03T09:00:00Z', '2026-03-04T11:00:00Z', '2026-02-25T00:00:00Z', '2026-03-02T00:00:00Z', '2026-03-03T00:00:00Z', true, '{"Jenkins Project","CISA"}', '{"jenkins","cicd","deserialization","rce","devops"}', 'Global'),

('Australia Cyber Security Centre Warns of Attacks on Critical Infrastructure OT Networks', 'acsc-australia-ot-critical-infrastructure', 'ACSC issues urgent advisory on increased targeting of Australian critical infrastructure OT networks by state-sponsored actors.', 'The Australian Cyber Security Centre has issued an urgent advisory warning of increased targeting of operational technology networks in Australian critical infrastructure by state-sponsored actors. The advisory covers water treatment, electricity generation, and port operations. ACSC has observed reconnaissance activity and initial access attempts using internet-exposed OT devices and VPN appliances. Organizations are urged to implement network segmentation and conduct OT security assessments.', 'medium', 'apt', '{}', '{"SCADA Systems","OT Networks","ICS Controllers","VPN Appliances"}', '{}', '{"energy","government","manufacturing","telecommunications"}', 'OT Device Exploitation / VPN Targeting', 'ACSC', 'https://www.cyber.gov.au', '2026-03-01T02:00:00Z', '2026-03-02T06:00:00Z', '2026-02-15T00:00:00Z', NULL, NULL, true, '{"ACSC","Five Eyes"}', '{"ot-security","critical-infrastructure","australia","state-sponsored","scada"}', 'Australia'),

('Interpol Operation Synergia II Dismantles 22,000 Malicious Servers Globally', 'interpol-synergia-ii-22k-servers', 'Interpol-led operation takes down 22,000 malicious servers across 100+ countries. 41 arrests made. Focus on phishing, ransomware, and infostealer infrastructure.', 'Interpol Operation Synergia II, conducted between January and March 2026, has resulted in the takedown of 22,000 malicious IP addresses and servers and 41 arrests across 100+ countries. The operation targeted infrastructure supporting phishing campaigns, ransomware operations, and information stealer malware. Key takedowns include bulletproof hosting providers in Eastern Europe and Southeast Asia. Interpol credits improved intelligence sharing with private sector partners including Group-IB, Trend Micro, and Kaspersky.', 'low', 'malware', '{}', '{"Malicious Infrastructure","Bulletproof Hosting","C2 Servers"}', '{}', '{"technology","government"}', 'N/A — Law Enforcement Operation', 'Interpol', 'https://www.interpol.int', '2026-02-28T10:00:00Z', '2026-03-01T08:00:00Z', NULL, NULL, NULL, true, '{"Interpol","Group-IB","Trend Micro"}', '{"law-enforcement","takedown","infrastructure","international","interpol"}', 'Global');
